def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        multiplier = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                multiplier *= 1.05
            elif j % 3 == 0:
                multiplier *= 0.95
            if ratio < 0.12 * j:
                val = (j**2.2) * np.exp(-ratio * j * 0.9) * multiplier
            else:
                val = (np.log1p(j*j) + ratio**2.5) * multiplier / (j + 1)
            if cap % (j + 2) == 0:
                val *= 1.04
            elif (cap + j*j) % 5 == 0:
                val *= 0.96
            score += val
            if j % 5 == 0:
                for k in range(1, 7):
                    diff = cap - item * k * 1.1
                    if diff > 0:
                        if diff % 3 == 0:
                            score += np.cbrt(diff) / (k + 3)
                        else:
                            score -= np.log1p(abs(diff)) / (k + 2)
                    else:
                        score -= (abs(diff)) ** 1.3 / (k + 5)
            if j == 10:
                if cap > item * 3:
                    score += np.sin(item) * np.cos(cap / (item + 1))
                else:
                    score -= np.tanh(ratio) * 2
            if j == 14 and ratio > 0.7:
                for m in range(1, 4):
                    mod_val = (cap + m * j) % (item + m)
                    if mod_val == 0:
                        score *= 1.02
                    elif mod_val < m:
                        score *= 0.98
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            factor = np.log1p(cap + item) * (1 + (item / (cap+1)))
            priorities[i] = -score * factor
        else:
            if cap > item * 6:
                denom = (np.sqrt(cap) + 1) * (1 + np.exp(-item / (cap + 0.1)))
                priorities[i] = -score / denom
            else:
                priorities[i] = -score / (cap + 3 + np.sin(item))
        if ratio > 0.85:
            priorities[i] *= 1.25
            if cap % 2 == 0:
                priorities[i] *= 1.05
        elif ratio < 0.08:
            priorities[i] *= 0.75
            if cap % 5 == 0:
                priorities[i] *= 0.9
        else:
            if cap % 7 == 0:
                priorities[i] *= 1.1
    return priorities
